module polynomial_evaluator (
    input [7:0] x,
    input [15:0] a0,
    input [15:0] a1,
    input [15:0] a2,
    input [15:0] a3,
    output [15:0] result
);
    wire [15:0] x1, x2, x3;
    wire [15:0] term1, term2, term3;

  assign result = a0 + x1 + term2 + term3;
  assign term3 = a3 * x3;
  assign x3 = x2 * x;
  assign term2 = a2 * x2;
  assign x2 = x * x;

  assign x1 = a1 * x;
endmodule
